"""
Scan every supported image in data/catalog/, extract dominant colours
with Pillow, and write data/metadata/products.json with one rich entry
per image.

Run from project root:
    python scripts/generate_metadata.py
"""
import colorsys
import json
import math
import os
from collections import Counter
from io import BytesIO
