# ── colour name mapping ──────────────────────────────────────────────────
# (hue_range_centre, min_S, min_V, name)
# Hue ranges: 0-360
# Colour wheel: red(0)→yellow(60)→green(120)→cyan(180)→blue(240)→magenta(300)→red(360)
_HUE_RANGES = [
    (0,   15,  "red"),
    (15,  40,  "orange"),
    (40,  70,  "yellow"),
    (70,  160, "green"),
    (160, 200, "cyan"),
    (200, 260, "blue"),
    (260, 310, "purple"),
    (310, 345, "pink"),
    (345, 360, "red"),
]


def _rgb_to_name(r: int, g: int, b: int) -> str:
    """Map an RGB tuple to an English colour name."""
    h, s, v = colorsys.rgb_to_hsv(r / 255.0, g / 255.0, b / 255.0)
    hue = h * 360
    if v < 0.15:
        return "black"
    if s < 0.12 and v > 0.85:
        return "white"
    if s < 0.15:
        return "gray" if v < 0.7 else "light gray"
    name = "red"
    for lo, hi, n in _HUE_RANGES:
        if lo <= hue < hi:
            name = n
            break
    if v < 0.45:
        name = f"dark {name}"
    elif v > 0.85 and s < 0.45:
        name = f"light {name}"
    return name


def _dominant_colours(img: Image.Image, n: int = 5, sample: int = 5000) -> list[str]:
    """Return the *n* most common colour names in an image."""
    small = img.copy()
    small.thumbnail((120, 120))
    pixels = list(small.getdata())
    if len(pixels) > sample:
        pixels = pixels[:sample]
    counter: Counter[tuple[int, int, int]] = Counter()
    for px in pixels:
        if isinstance(px, int):
            continue
        r, g, b = px[0], px[1], px[2]
        # quantise to reduce noise
        r, g, b = (r // 16) * 16, (g // 16) * 16, (b // 16) * 16
        counter[(r, g, b)] += 1
    names = []
    for (r, g, b), _ in counter.most_common(n * 3):
        name = _rgb_to_name(r, g, b)
        if name not in names:
            names.append(name)
        if len(names) >= n:
            break
    return names


def _has_pattern(img: Image.Image) -> str:
    """Very basic pattern detection via edge density."""
    import numpy as np
    small = img.copy()
    small.thumbnail((100, 100))
    gray = small.convert("L")
    arr = np.array(gray, dtype=float)
    gy, gx = np.gradient(arr)
    edges = np.sqrt(gx ** 2 + gy ** 2)
    density = float(np.mean(edges))
    if density > 45:
        return "printed"
    if density > 30:
        return "textured"
    return "solid"


# ── per-image metadata templates ──────────────────────────────────────────
# keyed by (category, numeric_id) → dict of attributes.
# Generated from actual visual inspection of each image file.

META: dict[tuple[str, int], dict] = {}


def _register(cat: str, items: list[dict]):
    for i, item in enumerate(items, 1):
        META[(cat, i)] = item


