# ── main ──────────────────────────────────────────────────────────────────

def _detect_pattern(img: Image.Image) -> str:
    """Use basic analysis to determine pattern."""
    try:
        import numpy as np
        small = img.copy()
        small.thumbnail((100, 100))
        gray = small.convert("L")
        arr = np.array(gray, dtype=float)
        gy, gx = np.gradient(arr)
        edges = np.sqrt(gx ** 2 + gy ** 2)
        density = float(np.mean(edges))
        if density > 50:
            return "printed"
        if density > 35:
            return "textured"
    except Exception:
        pass
    return "solid"


def build_metadata() -> list[dict]:
    supported = []
    for category_dir in sorted(CATALOG.iterdir()):
        if not category_dir.is_dir():
            continue
        category = category_dir.name
        for img_file in sorted(category_dir.iterdir()):
            if img_file.suffix.lower() not in SUPPORTED:
                continue
            supported.append((category, img_file))

    products = []
    for category, img_file in supported:
        stem = img_file.stem
        num = int("".join(c for c in stem if c.isdigit()))
        info = META.get((category, num), {})

        # extract dominant colours from the actual image
        try:
            with Image.open(str(img_file)) as img:
                colours = _dominant_colours(img, n=3)
                detected_pattern = _detect_pattern(img)
        except Exception:
            colours = []
            detected_pattern = "solid"

        primary = info.get("primary_color", colours[0] if len(colours) > 0 else "")
        secondary = info.get("secondary_color", colours[1] if len(colours) > 1 else "")

        pattern = info.get("pattern", "")
        if not pattern or pattern == "solid":
            pattern = detected_pattern if detected_pattern != "solid" else pattern or "solid"

        products.append({
            "id": stem,
            "name": info.get("name", f"{category.title()} {stem}"),
            "category": category,
            "primary_color": primary,
            "secondary_color": secondary,
            "color": primary,
            "pattern": pattern,
            "material": info.get("material", ""),
            "style": info.get("style", ""),
            "fit": info.get("fit", ""),
            "length": info.get("length", ""),
            "sleeve_type": info.get("sleeve_type", ""),
            "neckline": info.get("neckline", ""),
            "footwear_type": info.get("footwear_type", ""),
            "heel_type": info.get("heel_type", ""),
            "bag_type": info.get("bag_type", ""),
            "occasion": info.get("occasion", ""),
            "season": info.get("season", ""),
            "gender": info.get("gender", ""),
            "description": info.get("description", ""),
            "search_keywords": info.get("search_keywords", []),
        })

    return products


def main():
    products = build_metadata()
    OUT.parent.mkdir(parents=True, exist_ok=True)
    with open(OUT, "w", encoding="utf-8") as f:
        json.dump(products, f, indent=2, ensure_ascii=False)
    print(f"Wrote {len(products)} entries to {OUT}")

    # verify
    ids = [p["id"] for p in products]
    assert len(ids) == len(set(ids)), "Duplicate IDs found!"
    print("Verification: no duplicate IDs.")

    cats = {}
    for p in products:
        cats.setdefault(p["category"], []).append(p)
    for cat in sorted(cats):
        print(f"  {cat:9s}: {len(cats[cat])} products")


if __name__ == "__main__":
    main()
